import sys

def count_primes(n):
    if n < 3:
        return 0
    sieve = [True] * n
    sieve[0] = sieve[1] = False
    for i in range(2, int(n ** 0.5) + 1):
        if sieve[i]:
            for j in range(i * i, n, i):
                sieve[j] = False
    return sum(sieve)

if __name__ == '__main__':
    input_val = sys.stdin.read().strip()
    if input_val:
        n = int(input_val)
        print(count_primes(n))

