import sys

def longest_palindrome(s):
    if not s:
        return ""
    start, max_len = 0, 1
    def expand(l, r):
        while l >= 0 and r < len(s) and s[l] == s[r]:
            l -= 1
            r += 1
        return l + 1, r - l - 1
    for i in range(len(s)):
        l1, len1 = expand(i, i)
        l2, len2 = expand(i, i + 1)
        if len1 > max_len:
            max_len = len1
            start = l1
        if len2 > max_len:
            max_len = len2
            start = l2
    return s[start:start + max_len]

if __name__ == '__main__':
    s = sys.stdin.read().strip()
    print(longest_palindrome(s))

